def get_tmdb_catalog():
    """Return the full TMDB catalog"""
    return TMDB_CATALOG

def get_catalog_size():
    """Return catalog size"""
    return len(TMDB_CATALOG)

def get_movies_by_genre(genre_id):
    """Get movies filtered by genre"""
    return [m for m in TMDB_CATALOG if genre_id in m.get('genre_ids', [])]

def get_popular_movies(limit=20):
    """Get most popular movies (by vote_average × vote_count)"""
    scored = [(m, m.get('vote_average', 0) * m.get('vote_count', 0)) for m in TMDB_CATALOG]
    scored.sort(key=lambda x: x[1], reverse=True)
    return [m[0] for m in scored[:limit]]
